    (420, 'grammar_pattern', 'grammar', 'to be', 'Глагол to be помогает сказать, кто мы или какой предмет.', 2, array['grammar', 'to be']::text[], 'I am eight.', 'Глагол to be помогает сказать, кто мы или какой предмет.'),
