    (422, 'grammar_pattern', 'grammar', 'have got', 'Have got говорит, что у кого-то что-то есть.', 2, array['grammar', 'have-got']::text[], 'I have got a dog.', 'Have got говорит, что у кого-то что-то есть.'),
