    (428, 'grammar_pattern', 'grammar', 'articles a / an / the', 'a/an используется, когда предмет один и мы говорим о нем впервые. an используется перед словами, которые начинаются с гласного звука. the используется, когда мы уже знаем, о каком предмете говорим.', 2, array['grammar', 'articles']::text[], 'I have got a cat. The cat is black.', 'a/an используется, когда предмет один и мы говорим о нем впервые. an используется перед словами, которые начинаются с гласного звука. the используется, когда мы уже знаем, о каком предмете говорим.'),
    (429, 'grammar_pattern', 'grammar', 'plural nouns', 'Во множественном числе часто добавляем -s или -es.', 2, array['grammar', 'plural-nouns']::text[], 'one cat, two cats', 'Во множественном числе часто добавляем -s или -es.'),
    (430, 'grammar_pattern', 'grammar', 'possessives', 'My, your, her, his показывают, кому принадлежит предмет.', 2, array['grammar', 'possessives']::text[], 'my book', 'My, your, her, his показывают, кому принадлежит предмет.'),
    (431, 'grammar_pattern', 'grammar', 'prepositions', 'Предлоги помогают сказать, где находится предмет.', 2, array['grammar', 'prepositions']::text[], 'on the table', 'Предлоги помогают сказать, где находится предмет.'),
    (432, 'grammar_pattern', 'grammar', 'present simple routine', 'Present Simple помогает говорить о привычных делах.', 2, array['grammar', 'present-simple-routine']::text[], 'I go to school on Monday.', 'Present Simple помогает говорить о привычных делах.'),
    (433, 'grammar_pattern', 'grammar', 'classroom commands', 'Команды на уроке говорят, что нужно сделать.', 2, array['grammar', 'classroom-commands']::text[], 'Open your book.', 'Команды на уроке говорят, что нужно сделать.'),
    (434, 'grammar_pattern', 'grammar', 'imperatives with please', 'Please делает просьбу вежливой.', 2, array['grammar', 'polite-imperatives']::text[], 'Please open the door.', 'Please делает просьбу вежливой.'),
    (435, 'grammar_pattern', 'grammar', 'adjective + noun', 'Прилагательное обычно стоит перед существительным.', 2, array['grammar', 'adjective-noun']::text[], 'a red apple', 'Прилагательное обычно стоит перед существительным.'),
    (436, 'grammar_pattern', 'grammar', 'short answers', 'Короткие ответы зависят от вопроса.', 2, array['grammar', 'short-answers']::text[], 'Yes, I have.', 'Короткие ответы зависят от вопроса.'),
    (437, 'grammar_pattern', 'grammar', 'some with drinks', 'Some используем с напитками и едой, которую не считаем по одному.', 2, array['grammar', 'some-drinks']::text[], 'some juice', 'Some используем с напитками и едой, которую не считаем по одному.'),
    (438, 'grammar_pattern', 'grammar', 'days with on', 'С днями недели используем on.', 2, array['grammar', 'days-with-on']::text[], 'on Monday', 'С днями недели используем on.'),
    (439, 'grammar_pattern', 'grammar', 'be + feeling', 'С чувствами используем am, is или are.', 2, array['grammar', 'be-feeling']::text[], 'I am happy.', 'С чувствами используем am, is или are.'),
    (440, 'dialogue', 'simple questions', 'What''s your name?', 'My name is Anna.', 2, array['dialogue', 'speaking']::text[], 'What''s your name? My name is Anna.', 'Как тебя зовут? Меня зовут Анна.'),
    (441, 'dialogue', 'simple questions', 'How old are you?', 'I am eight.', 2, array['dialogue', 'speaking']::text[], 'How old are you? I am eight.', 'Сколько тебе лет? Мне восемь.'),
    (442, 'dialogue', 'simple questions', 'Have you got a pencil?', 'Yes, I have.', 2, array['dialogue', 'speaking']::text[], 'Have you got a pencil? Yes, I have.', 'У тебя есть карандаш? Да.'),
    (443, 'dialogue', 'simple questions', 'Have you got a dog?', 'No, I haven''t.', 2, array['dialogue', 'speaking']::text[], 'Have you got a dog? No, I haven''t.', 'У тебя есть собака? Нет.'),
    (444, 'dialogue', 'simple questions', 'Can you swim?', 'Yes, I can.', 2, array['dialogue', 'speaking']::text[], 'Can you swim? Yes, I can.', 'Ты умеешь плавать? Да.'),
    (445, 'dialogue', 'simple questions', 'Do you like apples?', 'Yes, I do.', 2, array['dialogue', 'speaking']::text[], 'Do you like apples? Yes, I do.', 'Ты любишь яблоки? Да.'),
    (446, 'dialogue', 'simple questions', 'Would you like some juice?', 'Yes, please.', 2, array['dialogue', 'speaking']::text[], 'Would you like some juice? Yes, please.', 'Хочешь сока? Да, пожалуйста.'),
    (447, 'dialogue', 'simple questions', 'Would you like some tea?', 'No, thank you.', 2, array['dialogue', 'speaking']::text[], 'Would you like some tea? No, thank you.', 'Хочешь чаю? Нет, спасибо.'),
    (448, 'dialogue', 'simple questions', 'Where is my bag?', 'It is on the chair.', 2, array['dialogue', 'speaking']::text[], 'Where is my bag? It is on the chair.', 'Где моя сумка? Она на стуле.'),
    (449, 'dialogue', 'simple questions', 'What is it?', 'It is a cat.', 2, array['dialogue', 'speaking']::text[], 'What is it? It is a cat.', 'Что это? Это кошка.'),
    (450, 'dialogue', 'polite requests', 'Who is this?', 'This is my brother.', 2, array['dialogue', 'speaking']::text[], 'Who is this? This is my brother.', 'Кто это? Это мой брат.'),
    (451, 'dialogue', 'polite requests', 'What colour is it?', 'It is blue.', 2, array['dialogue', 'speaking']::text[], 'What colour is it? It is blue.', 'Какого это цвета? Это синее.'),
    (452, 'dialogue', 'polite requests', 'Can you jump?', 'No, I can''t.', 2, array['dialogue', 'speaking']::text[], 'Can you jump? No, I can''t.', 'Ты умеешь прыгать? Нет.'),
    (453, 'dialogue', 'polite requests', 'Do you like milk?', 'No, I don''t.', 2, array['dialogue', 'speaking']::text[], 'Do you like milk? No, I don''t.', 'Ты любишь молоко? Нет.'),
    (454, 'dialogue', 'polite requests', 'Is it sunny today?', 'Yes, it is.', 2, array['dialogue', 'speaking']::text[], 'Is it sunny today? Yes, it is.', 'Сегодня солнечно? Да.'),
    (455, 'dialogue', 'polite requests', 'Are you happy?', 'Yes, I am.', 2, array['dialogue', 'speaking']::text[], 'Are you happy? Yes, I am.', 'Ты счастлив? Да.'),
    (456, 'dialogue', 'polite requests', 'How many cats are there?', 'There are two cats.', 2, array['dialogue', 'speaking']::text[], 'How many cats are there? There are two cats.', 'Сколько там кошек? Там две кошки.'),
    (457, 'dialogue', 'polite requests', 'Can I have a ruler, please?', 'Here you are.', 2, array['dialogue', 'speaking']::text[], 'Can I have a ruler, please? Here you are.', 'Можно мне линейку? Вот, держи.'),
    (458, 'dialogue', 'polite requests', 'Thank you.', 'You are welcome.', 2, array['dialogue', 'speaking']::text[], 'Thank you. You are welcome.', 'Спасибо. Пожалуйста.'),
    (459, 'dialogue', 'polite requests', 'Where is the book?', 'It is on the table.', 2, array['dialogue', 'speaking']::text[], 'Where is the book? It is on the table.', 'Где книга? Она на столе.'),
    (460, 'mini_story', 'animals', 'I have got a cat. The cat is black. The cat is happy.', 'У меня есть кошка. Кошка черная. Кошка счастливая.', 3, array['mini_story']::text[], 'I have got a cat. The cat is black. The cat is happy.', 'У меня есть кошка. Кошка черная. Кошка счастливая.'),
    (461, 'mini_story', 'food and drinks', 'I have got an apple. The apple is red. I like apples.', 'У меня есть яблоко. Яблоко красное. Я люблю яблоки.', 3, array['mini_story']::text[], 'I have got an apple. The apple is red. I like apples.', 'У меня есть яблоко. Яблоко красное. Я люблю яблоки.'),
    (462, 'mini_story', 'school', 'There is a book on the table. The book is blue.', 'На столе есть книга. Книга синяя.', 3, array['mini_story']::text[], 'There is a book on the table. The book is blue.', 'На столе есть книга. Книга синяя.'),
    (463, 'mini_story', 'school routine', 'I go to school on Monday. I have an English lesson.', 'Я хожу в школу в понедельник. У меня урок английского.', 3, array['mini_story']::text[], 'I go to school on Monday. I have an English lesson.', 'Я хожу в школу в понедельник. У меня урок английского.'),
    (464, 'mini_story', 'weather', 'It is sunny today. I can play in the park.', 'Сегодня солнечно. Я могу играть в парке.', 3, array['mini_story']::text[], 'It is sunny today. I can play in the park.', 'Сегодня солнечно. Я могу играть в парке.'),
    (465, 'mini_story', 'house and rooms', 'This is my room. There is a bed and a table. My bag is on the chair.', 'Это моя комната. Там есть кровать и стол. Моя сумка на стуле.', 3, array['mini_story']::text[], 'This is my room. There is a bed and a table. My bag is on the chair.', 'Это моя комната. Там есть кровать и стол. Моя сумка на стуле.'),
    (466, 'mini_story', 'toys', 'My sister has got a doll. The doll is small. It is pink.', 'У моей сестры есть кукла. Кукла маленькая. Она розовая.', 3, array['mini_story']::text[], 'My sister has got a doll. The doll is small. It is pink.', 'У моей сестры есть кукла. Кукла маленькая. Она розовая.'),
    (467, 'mini_story', 'food and drinks', 'I am hungry. I would like a sandwich and some juice.', 'Я голоден. Я бы хотел бутерброд и немного сока.', 3, array['mini_story']::text[], 'I am hungry. I would like a sandwich and some juice.', 'Я голоден. Я бы хотел бутерброд и немного сока.')
  ),
  inserted as (
  insert into public.cards (
    family_id, course_id, source_id, unit_id, lesson_id, deck_id, topic_id,
    english, russian, type, difficulty, tags, example_en, example_ru, status
  )
  select
    v_family, v_course, v_source, v_unit, v_lesson, v_deck, t.id,
    c.english, c.russian, c.type::public.card_type, c.difficulty, c.tags, c.example_en, c.example_ru, 'active'::public.card_status
  from seed_cards c
  join public.topics t on t.family_id = v_family and t.course_id = v_course and t.title = c.topic
  where not exists (
    select 1
    from public.cards existing
    where existing.family_id = v_family
      and existing.course_id = v_course
      and existing.source_id = v_source
      and lower(existing.english) = lower(c.english)
      and existing.type = c.type::public.card_type
  )
  returning id
  )
  select count(*) into v_inserted_cards from inserted;

  with seed_grammar(position, title, title_ru, pattern_key, pattern, explanation_ru, example_en, example_ru, affirmative_examples, negative_examples, question_examples, short_positive_answers, short_negative_answers, common_mistakes, exercise_templates) as (
  values
    (1, 'to be', 'to be', 'to be', 'am / is / are', 'Глагол to be помогает сказать, кто мы или какой предмет.', 'I am eight.', 'Глагол to be помогает сказать, кто мы или какой предмет.', '["I am eight.","She is happy.","They are pupils."]'::jsonb, '["I am not tired."]'::jsonb, '["Are you happy?","Is it a dog?"]'::jsonb, '["Yes, I am.","Yes, it is."]'::jsonb, '["No, I am not.","No, it isn''t."]'::jsonb, '[]'::jsonb, '[{"type":"question_form"},{"type":"short_answer"}]'::jsonb),
    (2, 'this is / that is', 'this is / that is', 'this-that', 'This is / That is', 'This is - это рядом. That is - это дальше.', 'This is my mum.', 'This is - это рядом. That is - это дальше.', '["This is my mum.","That is my bag."]'::jsonb, '[]'::jsonb, '["Who is this?","What is that?"]'::jsonb, '["It is my mum."]'::jsonb, '["It is not my bag."]'::jsonb, '[]'::jsonb, '[{"type":"question_form"},{"type":"short_answer"}]'::jsonb),
    (3, 'have got', 'have got', 'have-got', 'have got / has got', 'Have got говорит, что у кого-то что-то есть.', 'I have got a dog.', 'Have got говорит, что у кого-то что-то есть.', '["I have got a dog."]'::jsonb, '["I haven''t got a cat."]'::jsonb, '["Have you got a pencil?"]'::jsonb, '["Yes, I have."]'::jsonb, '["No, I haven''t."]'::jsonb, '[]'::jsonb, '[{"type":"question_form"},{"type":"short_answer"}]'::jsonb),
    (4, 'can', 'can', 'can', 'can + verb', 'Can говорит, что кто-то умеет или может что-то делать.', 'I can swim.', 'Can говорит, что кто-то умеет или может что-то делать.', '["I can swim."]'::jsonb, '["I can''t fly."]'::jsonb, '["Can you jump?"]'::jsonb, '["Yes, I can."]'::jsonb, '["No, I can''t."]'::jsonb, '[]'::jsonb, '[{"type":"question_form"},{"type":"short_answer"}]'::jsonb),
    (5, 'like', 'like', 'like', 'like / don''t like', 'Like говорит, что нам что-то нравится.', 'I like apples.', 'Like говорит, что нам что-то нравится.', '["I like apples."]'::jsonb, '["I don''t like milk."]'::jsonb, '["Do you like bananas?"]'::jsonb, '["Yes, I do."]'::jsonb, '["No, I don''t."]'::jsonb, '[]'::jsonb, '[{"type":"question_form"},{"type":"short_answer"}]'::jsonb),
    (6, 'would like', 'would like', 'would-like', 'would like + noun', 'I would like... - это вежливая фраза. Так говорят, когда хотят что-то попросить: еду, напиток или предмет.', 'I would like an apple.', 'I would like... - это вежливая фраза. Так говорят, когда хотят что-то попросить: еду, напиток или предмет.', '["I would like an apple.","I would like some juice."]'::jsonb, '["I would not like tea."]'::jsonb, '["Would you like some tea?","Would you like an orange?"]'::jsonb, '["Yes, please."]'::jsonb, '["No, thank you."]'::jsonb, '[]'::jsonb, '[{"type":"question_form"},{"type":"short_answer"}]'::jsonb),
    (7, 'there is / there are', 'there is / there are', 'there-is-there-are', 'There is / There are', 'There is для одного предмета, there are для нескольких.', 'There is a book on the table.', 'There is для одного предмета, there are для нескольких.', '["There is a book on the table.","There are two cats."]'::jsonb, '[]'::jsonb, '["Is there a book?","Are there two cats?"]'::jsonb, '["Yes, there is."]'::jsonb, '["No, there aren''t."]'::jsonb, '[]'::jsonb, '[{"type":"question_form"},{"type":"short_answer"}]'::jsonb),
    (8, 'what / where / who / how many', 'what / where / who / how many', 'wh-questions', 'Question word + question', 'What, where, who и how many помогают задавать простые вопросы.', 'What is it?', 'What, where, who и how many помогают задавать простые вопросы.', '["What is it?","Where is my pencil?","Who is this?"]'::jsonb, '[]'::jsonb, '["How many apples are there?"]'::jsonb, '["It is a cat."]'::jsonb, '["I don''t know."]'::jsonb, '[]'::jsonb, '[{"type":"question_form"},{"type":"short_answer"}]'::jsonb),
    (9, 'articles a / an / the', 'articles a / an / the', 'articles', 'a / an / the', 'a/an используется, когда предмет один и мы говорим о нем впервые. an используется перед словами, которые начинаются с гласного звука. the используется, когда мы уже знаем, о каком предмете говорим.', 'I have got a cat. The cat is black.', 'a/an используется, когда предмет один и мы говорим о нем впервые. an используется перед словами, которые начинаются с гласного звука. the используется, когда мы уже знаем, о каком предмете говорим.', '["I have got a cat. The cat is black.","I have got an apple. The apple is red.","The sun is yellow."]'::jsonb, '[]'::jsonb, '["Is it an apple?"]'::jsonb, '["Yes, it is."]'::jsonb, '["No, it isn''t."]'::jsonb, '[]'::jsonb, '[{"type":"question_form"},{"type":"short_answer"}]'::jsonb),
    (10, 'plural nouns', 'plural nouns', 'plural-nouns', 'one cat / two cats', 'Во множественном числе часто добавляем -s или -es.', 'one cat, two cats', 'Во множественном числе часто добавляем -s или -es.', '["one cat, two cats","one dog, three dogs","one box, two boxes"]'::jsonb, '[]'::jsonb, '["How many cats are there?"]'::jsonb, '["There are two cats."]'::jsonb, '["There is one cat."]'::jsonb, '[]'::jsonb, '[{"type":"question_form"},{"type":"short_answer"}]'::jsonb),
    (11, 'possessives', 'possessives', 'possessives', 'my / your / her / his', 'My, your, her, his показывают, кому принадлежит предмет.', 'my book', 'My, your, her, his показывают, кому принадлежит предмет.', '["my book","your pencil","her bag","his dog"]'::jsonb, '[]'::jsonb, '["Where is your pencil?"]'::jsonb, '["Here it is."]'::jsonb, '["It is not my book."]'::jsonb, '[]'::jsonb, '[{"type":"question_form"},{"type":"short_answer"}]'::jsonb),
    (12, 'prepositions', 'prepositions', 'prepositions', 'in / on / under / next to', 'Предлоги помогают сказать, где находится предмет.', 'on the table', 'Предлоги помогают сказать, где находится предмет.', '["on the table","under the chair","in the bag","next to the door"]'::jsonb, '[]'::jsonb, '["Where is the bag?"]'::jsonb, '["It is on the chair."]'::jsonb, '["It is not here."]'::jsonb, '[]'::jsonb, '[{"type":"question_form"},{"type":"short_answer"}]'::jsonb),
    (13, 'present simple routine', 'present simple routine', 'present-simple-routine', 'I go / I play / I do', 'Present Simple помогает говорить о привычных делах.', 'I go to school on Monday.', 'Present Simple помогает говорить о привычных делах.', '["I go to school on Monday.","I play football on Tuesday.","I do my homework in the evening."]'::jsonb, '[]'::jsonb, '["Do you play football?"]'::jsonb, '["Yes, I do."]'::jsonb, '["No, I don''t."]'::jsonb, '[]'::jsonb, '[{"type":"question_form"},{"type":"short_answer"}]'::jsonb),
    (14, 'classroom commands', 'classroom commands', 'classroom-commands', 'Open / Close / Listen', 'Команды на уроке говорят, что нужно сделать.', 'Open your book.', 'Команды на уроке говорят, что нужно сделать.', '["Open your book.","Close your book.","Listen and repeat.","Look at the board.","Sit down.","Stand up."]'::jsonb, '[]'::jsonb, '["Can you open your book?"]'::jsonb, '["Yes, I can."]'::jsonb, '["No, I can''t."]'::jsonb, '[]'::jsonb, '[{"type":"question_form"},{"type":"short_answer"}]'::jsonb),
    (15, 'imperatives with please', 'imperatives with please', 'polite-imperatives', 'Please + command', 'Please делает просьбу вежливой.', 'Please open the door.', 'Please делает просьбу вежливой.', '["Please open the door.","Please sit down."]'::jsonb, '[]'::jsonb, '["Can you help me, please?"]'::jsonb, '["Yes, of course."]'::jsonb, '["Sorry, I can''t."]'::jsonb, '[]'::jsonb, '[{"type":"question_form"},{"type":"short_answer"}]'::jsonb),
    (16, 'adjective + noun', 'adjective + noun', 'adjective-noun', 'a red apple', 'Прилагательное обычно стоит перед существительным.', 'a red apple', 'Прилагательное обычно стоит перед существительным.', '["a red apple","a big dog","a small room"]'::jsonb, '[]'::jsonb, '["What colour is the apple?"]'::jsonb, '["It is red."]'::jsonb, '["It is not red."]'::jsonb, '[]'::jsonb, '[{"type":"question_form"},{"type":"short_answer"}]'::jsonb),
    (17, 'short answers', 'short answers', 'short-answers', 'Yes, I do / No, I don''t', 'Короткие ответы зависят от вопроса.', 'Yes, I have.', 'Короткие ответы зависят от вопроса.', '["Yes, I have.","Yes, I can.","Yes, I do."]'::jsonb, '["No, I haven''t.","No, I can''t.","No, I don''t."]'::jsonb, '["Can you swim?","Do you like apples?"]'::jsonb, '["Yes, I can."]'::jsonb, '["No, I don''t."]'::jsonb, '[]'::jsonb, '[{"type":"question_form"},{"type":"short_answer"}]'::jsonb),
    (18, 'some with drinks', 'some with drinks', 'some-drinks', 'some juice / some milk', 'Some используем с напитками и едой, которую не считаем по одному.', 'some juice', 'Some используем с напитками и едой, которую не считаем по одному.', '["some juice","some milk","some tea"]'::jsonb, '[]'::jsonb, '["Would you like some juice?"]'::jsonb, '["Yes, please."]'::jsonb, '["No, thank you."]'::jsonb, '[]'::jsonb, '[{"type":"question_form"},{"type":"short_answer"}]'::jsonb),
    (19, 'days with on', 'days with on', 'days-with-on', 'on Monday', 'С днями недели используем on.', 'on Monday', 'С днями недели используем on.', '["on Monday","on Tuesday","on Sunday"]'::jsonb, '[]'::jsonb, '["Do you go to school on Monday?"]'::jsonb, '["Yes, I do."]'::jsonb, '["No, I don''t."]'::jsonb, '[]'::jsonb, '[{"type":"question_form"},{"type":"short_answer"}]'::jsonb),
    (20, 'be + feeling', 'be + feeling', 'be-feeling', 'I am happy', 'С чувствами используем am, is или are.', 'I am happy.', 'С чувствами используем am, is или are.', '["I am happy.","She is tired.","They are fine."]'::jsonb, '["I am not sad."]'::jsonb, '["Are you hungry?"]'::jsonb, '["Yes, I am."]'::jsonb, '["No, I am not."]'::jsonb, '[]'::jsonb, '[{"type":"question_form"},{"type":"short_answer"}]'::jsonb)
  ),
  updated as (
    update public.grammar_patterns gp
    set
      title_ru = sg.title_ru,
      pattern_key = sg.pattern_key,
      pattern = sg.pattern,
      explanation_ru = sg.explanation_ru,
      example_en = sg.example_en,
      example_ru = sg.example_ru,
      affirmative_examples = sg.affirmative_examples,
      negative_examples = sg.negative_examples,
      question_examples = sg.question_examples,
      short_positive_answers = sg.short_positive_answers,
      short_negative_answers = sg.short_negative_answers,
      common_mistakes = sg.common_mistakes,
      exercise_templates = sg.exercise_templates
    from seed_grammar sg
    where gp.family_id = v_family and gp.course_id = v_course and lower(gp.title) = lower(sg.title)
    returning gp.id
  ),
  inserted as (
    insert into public.grammar_patterns (
      family_id, course_id, title, title_ru, pattern_key, pattern, explanation_ru, example_en, example_ru,
      affirmative_examples, negative_examples, question_examples, short_positive_answers, short_negative_answers, common_mistakes, exercise_templates
    )
    select
      v_family, v_course, title, title_ru, pattern_key, pattern, explanation_ru, example_en, example_ru,
      affirmative_examples, negative_examples, question_examples, short_positive_answers, short_negative_answers, common_mistakes, exercise_templates
    from seed_grammar sg
    where not exists (
      select 1 from public.grammar_patterns gp
      where gp.family_id = v_family and gp.course_id = v_course and lower(gp.title) = lower(sg.title)
    )
    returning id
  )
  select count(*) into v_inserted_grammar from inserted;

  select count(*) into v_total_cards from public.cards where family_id = v_family and course_id = v_course and source_id = v_source;
  select count(*) into v_total_grammar from public.grammar_patterns where family_id = v_family and course_id = v_course;

  return jsonb_build_object(
    'inserted_cards', v_inserted_cards,
    'inserted_grammar_patterns', v_inserted_grammar,
    'total_cards', v_total_cards,
    'total_grammar_patterns', v_total_grammar,
    'course_title', 'Starter 350 Pre-A1'
  );
end;
$$;
